value.mensagem_usuario:
={{
  (() => {
    const raw = $('Seta Mensagem para o Agente').item.json.message || "";

    // Quebra em linhas
    let linhas = raw.split('\n').map(l => l.trim()).filter(l => l !== "");

    // Remove duplicadas mantendo a ordem
    let unicas = [...new Set(linhas)];

    // Junta novamente com uma quebra de linha normal
    return unicas.join('\n\n');
  })()
}}
